        map $server_port $fixed_target_host {
            default "";
            30346 "nvcr.io";
        }

        # The caching layer
        server {
            # Initialize logging variable first to prevent warnings
            set $docker_proxy_request_type "container-cache";

            log_by_lua_block {
                local cache_status = ngx.var.upstream_cache_status
                local request_uri = ngx.var.request_uri
                local request_method = ngx.var.request_method
                local body_size = ngx.var.body_bytes_sent
                local remote_addr = ngx.var.remote_addr
                local request_time = ngx.var.request_time
                local http_status = ngx.var.status
                if request_uri ~= nil and cache_status ~= nil and remote_addr ~= nil and not string.find(request_uri, "manifest") then
                    if request_time ~= nil then
                        http_request_time_ms_total:inc(tonumber(request_time), {request_method, cache_status, remote_addr, http_status})
                        http_requests_count:inc(1, {request_method, cache_status, remote_addr, http_status})

                        if body_size ~= nil then
                            cache_throughput:observe(tonumber(body_size) / tonumber(request_time), {cache_status, http_status})
                        end
                    end

                    if body_size ~= nil then
                        response_body_size:set(tonumber(body_size), {request_method, cache_status, remote_addr, http_status})
                    end
                end
            }
            # Listen on 13128 and optional CRI-O ports.
            listen 13128 ssl default_server;
            listen 30346 ssl;

            server_name proxy_caching_;

            set $disable_cache "3"; # Auth check yet to be performed

            # Hide/ignore headers from caching. S3 especially likes to send Expires headers in the past in some situations.
            proxy_hide_header      Set-Cookie;
            proxy_ignore_headers   X-Accel-Expires Expires Cache-Control Set-Cookie;

            # Logging config
            access_log  /var/log/nginx/access.log main;

            # Target Host config
            set_by_lua_block $target_host {
                local ns = ngx.var.arg_ns
                if ns == nil or ns == "" then
                    ns = ngx.var.fixed_target_host
                end
                -- Handle docker.io special case - redirect to registry-1.docker.io
                if ns == "docker.io" then
                    return "registry-1.docker.io"
                end
                -- Handle ECR pattern detection
                if string.match(ns, "%.dkr%.ecr%..*%.amazonaws%.com$") then
                    ngx.log(ngx.INFO, "ECR registry detected: " .. ns)
                    -- ECR tokens expire every 12 hours - consider shorter cache times
                end
                return ns
            }

            # Send upstream status as header
            add_header X-Docker-Registry-Proxy-Cache-Upstream-Status "$upstream_cache_status";

            # Use Generated certs
            ssl_verify_client optional;
            proxy_ssl_protocols TLSv1.2 TLSv1.3;
            ssl_protocols TLSv1.3;
            ssl_certificate /etc/certs/ssl-bundle.crt;
            ssl_certificate_key /etc/certs/leaf-ca.key;
            ssl_client_certificate /etc/ssl/certs/ca-certificates.crt;
            lua_ssl_trusted_certificate /etc/ssl/certs/ca-certificates.crt;
            ssl_certificate_by_lua_file /etc/nginx/conf.d/lua/lua-ssl.lua;
            # DNS resolver with aggressive caching for container registries (stable IPs)
            resolver local=on ipv6=off valid=1800s;  # 30min DNS cache - registries have very stable IPs

            chunked_transfer_encoding on;
            # Only GET from the Cache
            if ($request_method = POST) {
                return 405 "POST method is not allowed";
            }
            if ($request_method = PUT) {
                return 405 "PUT method is not allowed";
            }
            if ($request_method = DELETE) {
                return 405  "DELETE method is not allowed";
            }

            # If the request is for a /forcecache redirect, then we need to handle it specially.
            proxy_read_timeout 900;

            # Use cache locking
            # This forces additional requests to wait to be served through the cache
            # until the first request for the same resource is completed, helping cut bandwidth costs.
            proxy_cache_lock on;
            # Aligned with the canonical values in proxy-common.conf (this block does
            # not include that file).
            proxy_cache_lock_timeout 1200s;
            proxy_cache_lock_age 3600s;

            # Some extra settings to maximize cache hits and efficiency
            proxy_force_ranges on;
            proxy_ignore_client_abort on;
            proxy_cache_revalidate on;

            # Use SNI during the TLS handshake with the upstream.
            proxy_ssl_server_name on;

            # Verify SSL certs, and use the system CA bundle.
            proxy_ssl_verify on;
            proxy_ssl_trusted_certificate /etc/ssl/certs/ca-certificates.crt;
            proxy_ssl_verify_depth 2;
            proxy_ssl_session_reuse off;
            # Default cache validity - override for specific registries
            proxy_cache_valid 200 206 31d;

            # ECR-specific shorter cache times due to 12-hour token expiration  
            # Note: ECR auth validation will use shorter cache times automatically

            # Lua SSL config
            lua_ssl_verify_depth 2;


            # For blob requests by digest, do cache, and treat redirects.
            location ~ ^/v2/(.*)/blobs/sha256:(.*) {
                # Validate this client's right to read THIS resource before
                # serving cached content. The check has to be per-resource:
                # cached blobs are content-addressed by digest, so any
                # weaker scheme (e.g. probing the registry root) would let a
                # caller with a bearer scoped to repoA read a cached blob
                # that originally came from repoB -- which neutralises the
                # registry's authorization model.
                set $disable_cache "1"; # disabled to serve from cache by default
                access_by_lua_block {
                    local http = require "resty.http"
                    local httpc = http.new()
                    local auth_host = ngx.var.arg_ns
                    if auth_host == nil or auth_host == "" then
                        auth_host = ngx.var.fixed_target_host
                    end
                    -- Handle docker.io special case for auth validation
                    if auth_host == "docker.io" then
                        auth_host = "registry-1.docker.io"
                    end

                    local auth_header = ngx.var.http_authorization
                    if auth_header == nil or auth_header == "" then
                        -- Anonymous request. Do NOT enable the cache: there
                        -- are no credentials to validate, so we cannot
                        -- prove the caller has rights to anything cached.
                        -- The request falls through to upstream where the
                        -- registry's own auth policy applies; if the image
                        -- is public, containerd / CRI-O will negotiate a
                        -- bearer token via the WWW-Authenticate challenge
                        -- and retry, and that retry (which carries the
                        -- bearer) goes through this probe and may hit cache.
                        ngx.log(ngx.INFO,
                            "Anonymous request; cache bypassed (no creds to validate). uri=",
                            ngx.var.request_uri)
                        return
                    end

                    -- Per-resource HEAD: ask the registry "given my creds,
                    -- am I allowed to read this exact URI?". Authenticated
                    -- 200/3xx means yes (3xx covers Docker Hub redirecting
                    -- blobs to S3 -- the redirect itself proves the bearer
                    -- was accepted); anything else means no.
                    local probe_url = "https://" .. auth_host .. ngx.var.request_uri
                    local res, err = httpc:request_uri(probe_url, {
                        method = "HEAD",
                        headers = {
                            ["Authorization"] = auth_header
                        }
                    })

                    if res and res.status >= 200 and res.status < 400 then
                        ngx.log(ngx.INFO, "Per-resource auth ok (status ", res.status, "); cache enabled.")
                        ngx.var.disable_cache = "0"
                    else
                        local s = res and tostring(res.status) or ("err: " .. tostring(err))
                        ngx.log(ngx.WARN,
                            "Per-resource auth failed (", s, "); cache bypassed. uri=",
                            ngx.var.request_uri)
                    end
                }

                proxy_cache_bypass $disable_cache;
                # Also block cache writes when $disable_cache="1". `bypass`
                # alone only skips reads -- without `no_cache`, a probe-failed
                # response would still be stored.
                proxy_no_cache $disable_cache;
                set $docker_proxy_request_type "blob-by-digest";
                proxy_pass https://$target_host;
                proxy_set_header Host $target_host;
                add_header X-Docker-Registry-Proxy-Cache-Upstream-Status "$upstream_cache_status";
                add_header X-Docker-Registry-Proxy-Cache-Type "$docker_proxy_request_type";
                proxy_set_header X-Real-IP $remote_addr;
                proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
                proxy_set_header X-Forwarded-Proto $scheme;
                proxy_cache container;
                proxy_cache_key   $uri;
                proxy_intercept_errors on;

                # Defensive: if upstream returns text/html for a blob-by-digest
                # path -- which Docker Hub does on rate-limit (429) or service
                # error pages, and which the OCI distribution spec never
                # produces -- mark the response not-cacheable so the rate-limit
                # HTML page can't poison subsequent reads. The status itself
                # passes through to the client.
                header_filter_by_lua_block {
                    local ct = ngx.header["Content-Type"] or ngx.header["content-type"]
                    if ct and string.find(string.lower(ct), "text/html", 1, true) then
                        ngx.log(ngx.WARN,
                            "Upstream returned text/html on a registry blob path; not caching. ",
                            "uri=", ngx.var.request_uri, " host=", ngx.var.target_host,
                            " upstream_status=", ngx.var.upstream_status)
                        ngx.var.disable_cache = "1"
                    end
                }

                # enables revalidation of expired cached responses using conditional GET requests.
                proxy_cache_revalidate on;
                # allows serving stale content from the cache while Nginx is updating the cache in the background.
                proxy_cache_use_stale updating;

                # Skip redirect handling for GCR to avoid relative URL issues
                set_by_lua_block $skip_redirects {
                    local ns = ngx.var.arg_ns
                    if ns == "gcr.io" then
                        return "1"
                    else
                        return "0"
                    end
                }

                # Only handle redirects for non-GCR registries
                if ($skip_redirects = "0") {
                    error_page 301 302 307 = @handle_redirects;
                }
            }

            # For manifest requests by digest, do cache, and treat redirects.
            location ~ ^/v2/(.*)/manifests/sha256:(.*) {
                # Validate credentials before serving manifests. See the
                # comment on the blobs-by-digest location above for the
                # full rationale (per-resource auth, no anonymous-cache).
                set $disable_cache "1"; # disabled to serve from cache by default
                access_by_lua_block {
                    local http = require "resty.http"
                    local httpc = http.new()
                    local auth_host = ngx.var.arg_ns
                    if auth_host == nil or auth_host == "" then
                        auth_host = ngx.var.fixed_target_host
                    end
                    if auth_host == "docker.io" then
                        auth_host = "registry-1.docker.io"
                    end

                    local auth_header = ngx.var.http_authorization
                    if auth_header == nil or auth_header == "" then
                        ngx.log(ngx.INFO,
                            "Anonymous request; cache bypassed (no creds to validate). uri=",
                            ngx.var.request_uri)
                        return
                    end

                    local probe_url = "https://" .. auth_host .. ngx.var.request_uri
                    local res, err = httpc:request_uri(probe_url, {
                        method = "HEAD",
                        headers = {
                            ["Authorization"] = auth_header
                        }
                    })

                    if res and res.status >= 200 and res.status < 400 then
                        ngx.log(ngx.INFO, "Per-resource auth ok (status ", res.status, "); cache enabled.")
                        ngx.var.disable_cache = "0"
                    else
                        local s = res and tostring(res.status) or ("err: " .. tostring(err))
                        ngx.log(ngx.WARN,
                            "Per-resource auth failed (", s, "); cache bypassed. uri=",
                            ngx.var.request_uri)
                    end
                }

                set $docker_proxy_request_type "manifest-by-digest";
                add_header X-Docker-Registry-Proxy-Cache-Upstream-Status "$upstream_cache_status";
                add_header X-Docker-Registry-Proxy-Cache-Type "$docker_proxy_request_type";
                proxy_set_header X-Real-IP $remote_addr;
                proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
                proxy_set_header X-Forwarded-Proto $scheme;
                proxy_cache_bypass $disable_cache;
                proxy_no_cache $disable_cache;
                proxy_pass https://$target_host;
                proxy_set_header Host $target_host;
                proxy_cache container;
                proxy_cache_key $uri;
                proxy_intercept_errors on;
                # See blob-by-digest above for the same content-type guard.
                header_filter_by_lua_block {
                    local ct = ngx.header["Content-Type"] or ngx.header["content-type"]
                    if ct and string.find(string.lower(ct), "text/html", 1, true) then
                        ngx.log(ngx.WARN,
                            "Upstream returned text/html on a registry manifest path; not caching. ",
                            "uri=", ngx.var.request_uri, " host=", ngx.var.target_host,
                            " upstream_status=", ngx.var.upstream_status)
                        ngx.var.disable_cache = "1"
                    end
                }
                error_page 301 302 307 = @handle_redirects;
            }

            location ~ ^/v2/(.*)/manifests/ {
                set $docker_proxy_request_type "manifest-caching-disabled";
                proxy_pass https://$target_host;
                proxy_set_header Host $target_host;
                proxy_set_header Authorization $http_authorization;
                proxy_set_header X-Real-IP $remote_addr;
                proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
                proxy_set_header X-Forwarded-Proto $scheme;
                # Do not Cache Manifests
                proxy_cache off;
            }

            # Cache blobs requests that are not by digest
            # Since these are mutable, we invalidate them immediately and keep them only in case the backend is down
            location ~ ^/v2/(.*)/blobs/ {
                set $docker_proxy_request_type "blob-mutable";
                proxy_cache_valid 0s;
                proxy_pass https://$target_host;
                proxy_set_header Host $target_host;
                proxy_set_header X-Real-IP $remote_addr;
                proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
                proxy_set_header X-Forwarded-Proto $scheme;
                # Cache blobs
                proxy_cache container;
                # enables revalidation of expired cached responses using conditional GET requests.
                proxy_cache_revalidate on;
                # allows serving stale content from the cache while Nginx is updating the cache in the background.
                proxy_cache_use_stale updating;
                proxy_cache_use_stale  error timeout http_500 http_502 http_504 http_429;
            }

            location @handle_redirects {
                set $docker_proxy_request_type "handle-redirect";
                set $original_uri $uri;
                set $orig_loc $upstream_http_location;

                # Fix relative URLs from GCR and other registries using access phase
                access_by_lua_block {
                    local location = ngx.var.upstream_http_location
                    local target_host = ngx.var.target_host

                    if location and string.sub(location, 1, 1) == "/" then
                        -- Relative URL - convert to absolute
                        ngx.var.orig_loc = "https://" .. target_host .. location
                        ngx.log(ngx.INFO, "GCR redirect fix: " .. target_host .. " + " .. location .. " = " .. ngx.var.orig_loc)
                    end
                }

                proxy_set_header Authorization "";
                proxy_pass $orig_loc;
                proxy_cache container;
                proxy_cache_key $original_uri;
            }

            location / {
                proxy_set_header Authorization $http_authorization;
                proxy_set_header Host $target_host;
                proxy_set_header X-Real-IP $remote_addr;
                proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
                proxy_set_header X-Forwarded-Proto $scheme;
                proxy_cache off;
                proxy_pass https://$target_host;
            }
        }

