                    end
                }

                # enables revalidation of expired cached responses using conditional GET requests.
                proxy_cache_revalidate on;
                # allows serving stale content from the cache while Nginx is updating the cache in the background.
                proxy_cache_use_stale updating;

                # Skip redirect handling for GCR to avoid relative URL issues
                set_by_lua_block $skip_redirects {
                    local ns = ngx.var.arg_ns
                    if ns == "gcr.io" then
                        return "1"
                    else
                        return "0"
                    end
                }

                # Only handle redirects for non-GCR registries
                if ($skip_redirects = "0") {
                    error_page 301 302 307 = @handle_redirects;
                }
            }

            # For manifest requests by digest, do cache, and treat redirects.
            location ~ ^/v2/(.*)/manifests/sha256:(.*) {
                # Validate credentials before serving manifests. See the
                # comment on the blobs-by-digest location above for the
                # full rationale (per-resource auth, no anonymous-cache).
                set $disable_cache "1"; # disabled to serve from cache by default
                access_by_lua_block {
                    local http = require "resty.http"
                    local httpc = http.new()
                    local auth_host = ngx.var.arg_ns
                    if auth_host == nil or auth_host == "" then
                        auth_host = ngx.var.fixed_target_host
                    end
                    if auth_host == "docker.io" then
                        auth_host = "registry-1.docker.io"
                    end

                    local auth_header = ngx.var.http_authorization
                    if auth_header == nil or auth_header == "" then
                        ngx.log(ngx.INFO,
                            "Anonymous request; cache bypassed (no creds to validate). uri=",
                            ngx.var.request_uri)
                        return
                    end

                    local probe_url = "https://" .. auth_host .. ngx.var.request_uri
                    local res, err = httpc:request_uri(probe_url, {
                        method = "HEAD",
                        headers = {
                            ["Authorization"] = auth_header
                        }
                    })

                    if res and res.status >= 200 and res.status < 400 then
                        ngx.log(ngx.INFO, "Per-resource auth ok (status ", res.status, "); cache enabled.")
                        ngx.var.disable_cache = "0"
                    else
                        local s = res and tostring(res.status) or ("err: " .. tostring(err))
                        ngx.log(ngx.WARN,
                            "Per-resource auth failed (", s, "); cache bypassed. uri=",
                            ngx.var.request_uri)
                    end
                }

                set $docker_proxy_request_type "manifest-by-digest";
                add_header X-Docker-Registry-Proxy-Cache-Upstream-Status "$upstream_cache_status";
                add_header X-Docker-Registry-Proxy-Cache-Type "$docker_proxy_request_type";
                proxy_set_header X-Real-IP $remote_addr;
                proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
                proxy_set_header X-Forwarded-Proto $scheme;
                proxy_cache_bypass $disable_cache;
                proxy_no_cache $disable_cache;
                proxy_pass https://$target_host;
                proxy_set_header Host $target_host;
                proxy_cache container;
                proxy_cache_key $uri;
                proxy_intercept_errors on;
                # See blob-by-digest above for the same content-type guard.
                header_filter_by_lua_block {
                    local ct = ngx.header["Content-Type"] or ngx.header["content-type"]
                    if ct and string.find(string.lower(ct), "text/html", 1, true) then
                        ngx.log(ngx.WARN,
                            "Upstream returned text/html on a registry manifest path; not caching. ",
                            "uri=", ngx.var.request_uri, " host=", ngx.var.target_host,
                            " upstream_status=", ngx.var.upstream_status)
                        ngx.var.disable_cache = "1"
                    end
                }
                error_page 301 302 307 = @handle_redirects;
            }

            location ~ ^/v2/(.*)/manifests/ {
                set $docker_proxy_request_type "manifest-caching-disabled";
                proxy_pass https://$target_host;
                proxy_set_header Host $target_host;
                proxy_set_header Authorization $http_authorization;
                proxy_set_header X-Real-IP $remote_addr;
                proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
                proxy_set_header X-Forwarded-Proto $scheme;
                # Do not Cache Manifests
                proxy_cache off;
            }

            # Cache blobs requests that are not by digest
            # Since these are mutable, we invalidate them immediately and keep them only in case the backend is down
            location ~ ^/v2/(.*)/blobs/ {
                set $docker_proxy_request_type "blob-mutable";
                proxy_cache_valid 0s;
                proxy_pass https://$target_host;
                proxy_set_header Host $target_host;
                proxy_set_header X-Real-IP $remote_addr;
                proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
                proxy_set_header X-Forwarded-Proto $scheme;
                # Cache blobs
                proxy_cache container;
                # enables revalidation of expired cached responses using conditional GET requests.
                proxy_cache_revalidate on;
                # allows serving stale content from the cache while Nginx is updating the cache in the background.
                proxy_cache_use_stale updating;
                proxy_cache_use_stale  error timeout http_500 http_502 http_504 http_429;
            }

            location @handle_redirects {
                set $docker_proxy_request_type "handle-redirect";
                set $original_uri $uri;
                set $orig_loc $upstream_http_location;

                # Fix relative URLs from GCR and other registries using access phase
                access_by_lua_block {
                    local location = ngx.var.upstream_http_location
                    local target_host = ngx.var.target_host

                    if location and string.sub(location, 1, 1) == "/" then
                        -- Relative URL - convert to absolute
                        ngx.var.orig_loc = "https://" .. target_host .. location
                        ngx.log(ngx.INFO, "GCR redirect fix: " .. target_host .. " + " .. location .. " = " .. ngx.var.orig_loc)
                    end
                }

                proxy_set_header Authorization "";
                proxy_pass $orig_loc;
                proxy_cache container;
                proxy_cache_key $original_uri;
            }

            location / {
                proxy_set_header Authorization $http_authorization;
                proxy_set_header Host $target_host;
                proxy_set_header X-Real-IP $remote_addr;
                proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
                proxy_set_header X-Forwarded-Proto $scheme;
                proxy_cache off;
                proxy_pass https://$target_host;
            }
        }
